import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklyPattern {
  day: string;
  cups: number;
}

interface CaffeineData {
  todayConsumption: {
    cups: number;
    caffeineIntakeMg: number;
  };
  weeklyPattern: WeeklyPattern[];
}

export default function Widget() {
  const caffeineData = response.data as CaffeineData;
  const { todayConsumption, weeklyPattern } = caffeineData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 3 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Today's Caffeine Intake
            </Typography>
            <Typography variant="h4" sx={{ color: '#F8FAFC', fontWeight: 700 }}>
              {todayConsumption.cups} cups
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              {todayConsumption.caffeineIntakeMg} mg
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 160 }}>
            <BarChart
              height={140}
              series={[
                {
                  data: weeklyPattern.map(d => d.cups),
                  color: '#3B82F6',
                },
              ]}
              xAxis={[
                {
                  data: weeklyPattern.map(d => d.day),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#9CA3AF',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
